import React, { useEffect, useState } from 'react';
import { getSitios, deleteSitio, createSitio, updateSitio } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);
  const [editandoId, setEditandoId] = useState(null); // Para saber si estamos creando o editando
  const [nuevoSitio, setNuevoSitio] = useState({ nombre: '', descripcion: '', ubicacion: '' });

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const datos = await getSitios();
    setSitios(datos);
  };

  const handleChange = (e) => {
    setNuevoSitio({ ...nuevoSitio, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (editandoId) {
        await updateSitio(editandoId, nuevoSitio);
        setEditandoId(null);
    } else {
        await createSitio(nuevoSitio);
    }
    setNuevoSitio({ nombre: '', descripcion: '', ubicacion: '' });
    cargarDatos();
  };

  const prepararEdicion = (sitio) => {
    setEditandoId(sitio._id);
    setNuevoSitio({
        nombre: sitio.nombre,
        descripcion: sitio.descripcion,
        ubicacion: sitio.ubicacion
    });
    window.scrollTo(0, 0); // Sube al formulario
  };

  const eliminar = async (id) => {
    if(window.confirm('¿Deseas eliminar este sitio?')) {
      await deleteSitio(id);
      cargarDatos();
    }
  };

  return (
    <div style={{ padding: '20px', backgroundColor: '#f4f4f4', minHeight: '100vh', fontFamily: 'Arial' }}>
      <header style={{ textAlign: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: '#d9534f' }}>Cultura La Paz - Panel de Control</h1>
      </header>

      <div style={{ backgroundColor: 'white', padding: '20px', borderRadius: '10px', maxWidth: '600px', margin: '0 auto 40px auto', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
        <h3 style={{ textAlign: 'center' }}>{editandoId ? '📝 Editando Sitio' : '➕ Registrar Nuevo Sitio'}</h3>
        <form onSubmit={handleSubmit}>
          <input style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }} name="nombre" placeholder="Nombre" value={nuevoSitio.nombre} onChange={handleChange} required />
          <textarea style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }} name="descripcion" placeholder="Descripción" value={nuevoSitio.descripcion} onChange={handleChange} required />
          <input style={{ width: '100%', padding: '10px', marginBottom: '10px', borderRadius: '5px', border: '1px solid #ddd' }} name="ubicacion" placeholder="Ubicación" value={nuevoSitio.ubicacion} onChange={handleChange} required />
          <button type="submit" style={{ width: '100%', padding: '10px', backgroundColor: editandoId ? '#f0ad4e' : '#5cb85c', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
            {editandoId ? 'Actualizar Cambios' : 'Guardar Sitio'}
          </button>
          {editandoId && <button onClick={() => {setEditandoId(null); setNuevoSitio({nombre:'', descripcion:'', ubicacion:''})}} style={{ width: '100%', marginTop: '5px', padding: '5px', background: 'none', border: 'none', color: 'gray', cursor: 'pointer' }}>Cancelar</button>}
        </form>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px', maxWidth: '1200px', margin: '0 auto' }}>
        {sitios.map(sitio => (
          <div key={sitio._id} style={{ backgroundColor: 'white', padding: '20px', borderRadius: '10px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
            <h3>{sitio.nombre}</h3>
            <p>{sitio.descripcion}</p>
            <p>📍 {sitio.ubicacion}</p>
            <div style={{ display: 'flex', gap: '10px' }}>
                <button onClick={() => prepararEdicion(sitio)} style={{ backgroundColor: '#f0ad4e', color: 'white', border: 'none', padding: '10px', borderRadius: '5px', cursor: 'pointer', flex: 1 }}>Editar</button>
                <button onClick={() => eliminar(sitio._id)} style={{ backgroundColor: '#d9534f', color: 'white', border: 'none', padding: '10px', borderRadius: '5px', cursor: 'pointer', flex: 1 }}>Eliminar</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
